package com.google.gson.internal;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.mockito.Mockito.mock;

import java.lang.reflect.Type;

import org.junit.jupiter.api.Test;

class $Gson$TypesTest {

  @Test
  void typeToString_withClassType_returnsClassName() {
    Class<String> clazz = String.class;
    String result = $Gson$Types.typeToString(clazz);
    assertEquals("java.lang.String", result);
  }

  @Test
  void typeToString_withNonClassType_returnsToString() {
    Type mockedType = mock(Type.class);
    String toStringValue = "mockedTypeToString";
    // Mockito when-thenReturn for toString() is not directly possible, so create anonymous Type
    Type anonymousType = new Type() {
      @Override
      public String toString() {
        return toStringValue;
      }
    };
    String result = $Gson$Types.typeToString(anonymousType);
    assertEquals(toStringValue, result);
  }
}
